"use strict";(self.webpackChunkbo_bi_co_website=self.webpackChunkbo_bi_co_website||[]).push([["1705"],{1323(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/06/10/release","metadata":{"permalink":"/updates/2026/06/10/release","source":"@site/blog/updates/2026-06-10-release.mdx","title":"BoBiCo Shader 1.0 Release.","description":"After over 3 months of development. We\'re so glad to introduce the 1.0 version of our BoBiCo shader. Our first release of the shader.","date":"2026-06-10T00:00:00.000Z","tags":[],"readingTime":1.56,"hasTruncateMarker":false,"authors":[{"name":"\u4E43\u3116\u4E43\u722A\u5342\u531A \xdc","title":"BoBiCo Shader Developer/Documentation Author","socials":{"github":"https://github.com/BobmacU","youtube":"https://youtube.com/@Bobmacjefferson"},"imageURL":"/img/authors/bobmac.png","key":"bobmac","page":null}],"frontMatter":{"title":"BoBiCo Shader 1.0 Release.","authors":["bobmac"]},"unlisted":false},"content":"After over **3** months of development. We\'re so glad to introduce the **1.0** version of our **BoBiCo** shader. Our first release of the shader.\\nOur shader is now available on **S&box Workshop**, **Github** and **Discord**. Fully open-source in **MIT** license!\\n\\n## [Download from here!](/docs/general-info/download-and-usage)\\n\\n---\\n\\n## \u2728 Feature Highlights\\n\\n### \u{1F3A8} Multiple Shading Styles\\nBoBiCo Shader comes with six built-in shading modes: Flat, Multilayer, Texture Ramp, Shade Map, Realistic, and Fur.\\n\\nEvery shading mode also supports Wrap Shading, allowing you to easily achieve different lighting styles without switching to another shader.\\n\\n### \u{1FA9F} Flexible Rendering Modes\\nSupports Opaque, Cutout, and Transparent rendering pipelines, alongside advanced transparency techniques such as Dither Alpha, Alpha-to-Coverage, and Fresnel Alpha.\\n\\nThe shader intelligently reuses existing alpha channels whenever possible, reducing the need for dedicated masking textures.\\n\\n### \u{1F4A1} Full Lighting Support\\nDesigned to integrate seamlessly with the S&box lighting pipeline, supporting Direct Lighting, Indirect Lighting, Light Probes, and DDGI.\\n\\nLighting transitions adapt naturally to the environment while preserving the intended visual style.\\n\\n### \u{1F39B}\uFE0F Extensive Material Customization\\nBuild highly customizable materials using dual main color layers, built-in decal tools, normal maps, emission, matcaps, and a large collection of color adjustment controls.\\n\\nWhether you\'re creating stylized or realistic materials, the shader provides plenty of flexibility without becoming difficult to use.\\n\\n### \u2728 Stylized Effects\\nEnhance your visuals with built-in features including MatCaps, Inverted Hull Outlines, Glitter Effects, and several additional NPR-oriented rendering options.\\n\\n### \u2699\uFE0F Physically Based Rendering\\nEvery shading mode except Fur supports a complete PBR workflow, including advanced material parameters and flexible multi-channel controls for fine-tuning surface appearance.\\n\\n### \u{1F680} Advanced Features\\nBoBiCo Shader also includes support for Screen Space Ambient Occlusion (SSAO), Parallax Occlusion Mapping, Self Shadowing, Subsurface Scattering, Fur Rendering, and many other advanced rendering techniques\\n\\nSee our **Documentation** for full detailed documentation about the features our shader offers!\\nThank you for using our shader :)\\n\\n---"}]}}')}}]);